-- Process change: require a tagged backup before any production DELETE.
-- Use psql's \set ECHO_QUERIES for verbose confirmation, and require a peer review.

\set AUTOCOMMIT off
SELECT count(*) FROM users WHERE id = 5042;          -- confirm 1 user matches
SELECT count(*) FROM orders WHERE user_id = 5042;    -- check downstream impact
-- pg_dump users orders ...                          -- backup
DELETE FROM users WHERE id = 5042;
ROLLBACK;                                            -- mandatory dry-run first
-- ... peer review of the dry-run output ...
BEGIN;
DELETE FROM users WHERE id = 5042;
COMMIT;

BEGIN;

DELETE FROM users WHERE id = 5042;

-- Postgres doesn't directly count cascaded rows in this transaction;
-- check downstream impact manually:
SELECT count(*) FROM orders WHERE user_id = 5042;   -- → 0 (already deleted)

-- Hmm, no obvious way to know how many cascaded rows were deleted before commit.
-- Try: SELECT pg_stat_xact_user_tables ... (complicated, brittle).

-- If looks-fine:
COMMIT;
